patch_segments.append_text:
.thesis-hero{margin:1.5rem auto 1.75rem;max-width:64rem;padding:0 .5rem;text-align:center}
.thesis-claim{font-family:var(--serif);font-size:clamp(2.0rem,5vw,3.4rem);line-height:1.18;color:var(--heading);font-weight:600;letter-spacing:-0.01em;margin:0 auto .9rem;max-width:36ch;text-wrap:balance}
.thesis-stat-row{display:grid;grid-template-columns:repeat(4,1fr);gap:1.1rem;margin:1.1rem auto 0;padding:.85rem 0 0;border-top:1px solid var(--rule);max-width:60rem;font-family:var(--sans)}
.thesis-stat-row > div{margin:0;padding:0;display:flex;flex-direction:column;align-items:center;gap:.2rem}
.thesis-stat .thesis-stat-num{font-family:var(--serif);font-size:1.45rem;font-weight:700;color:var(--heading);margin:0;line-height:1.05;font-variant-numeric:tabular-nums}
.thesis-stat .thesis-stat-num-words{font-size:1.1rem;font-weight:700;letter-spacing:0;text-transform:none}
.thesis-stat .thesis-stat-cap{margin:0;font-size:.74rem;font-weight:600;color:var(--ink-3);text-transform:uppercase;letter-spacing:0.08em;line-height:1.3;max-width:18ch}
.thesis-stat .thesis-stat-cap a{color:inherit;text-decoration:none;border-bottom:1px solid var(--rule);transition:color .15s,border-color .15s}
.thesis-stat .thesis-stat-cap a:hover{color:var(--accent);border-bottom-color:var(--accent)}
.thesis-stat-accent .thesis-stat-num{color:var(--accent)}
@media(max-width:900px){.thesis-stat-row{grid-template-columns:repeat(2,1fr);gap:.85rem}}
@media(max-width:520px){.thesis-stat-row{grid-template-columns:1fr;gap:.65rem}.thesis-claim{font-size:clamp(1.6rem,7vw,2.4rem);max-width:24ch}}
